// Shape Shifter -- shape grid, osc modulation, chromatic aberration
speed = 0.6

AUDIO.bins = 6; AUDIO.smooth = 0.80; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// o1: shape grid base
shape(6, 0.2, 0.03)
  .repeat(5, 4, () => Math.sin(time * 0.06) * 0.08, () => Math.cos(time * 0.05) * 0.06)
  .rotate(() => time * 0.02)
  .color(
    () => 0.9 + low() * 0.5,
    () => 0.4 + mid() * 0.5,
    () => 0.7 + high() * 0.4
  )
  .modulate(osc(8, 0.04, 1.0), () => 0.05 + low() * 0.006)
  .modulate(noise(2, 0.1), () => 0.03 + mid() * 0.004)
  .out(o1)

// o0: chromatic aberration + feedback
src(o1)
  .r().scrollX(() => 0.002 + low() * 0.001)
  .color(1.0, 0.08, 0.05)
  .add(
    src(o1).g()
      .scrollX(() => -(0.001 + mid() * 0.0008))
      .color(0.15, 0.95, 0.1)
  )
  .add(
    src(o1).b()
      .scrollY(() => 0.001 + high() * 0.0006)
      .color(0.05, 0.12, 0.9)
  )
  .blend(src(o0).rotate(() => Math.sin(time * 0.03) * 0.003).hue(() => amp() * 0.005), 0.76)
  .saturate(() => 1.25 + low() * 0.35)
  .colorama(() => 0.001 + amp() * 0.003)
  .contrast(() => 1.04 + low() * 0.06)
  .brightness(0.03)
  .out(o0)
